UPDATE
    member
SET
    point = point + #{amount}
WHERE
    id = #{id};

mapper.insert:
INSERT INTO member (
username, password, name, nickname, email, role, status, created_at
) VALUES ( #{username}, #{password}, #{name}, #{nickname}, #{email}, #{role}, #{status}, NOW() )

mapper.update:
UPDATE member
name = #{name}, email = #{email}, image_url = #{imageUrl}, nickname = #{nickname},
WHERE id = #{id}

UPDATE member
SET name = #{name},
    nickname = #{nickname},
    image_url = #{imageUrl},
    status = #{status}
WHERE username = #{username}

mapper.select:
