SELECT id, nickname, email, status, created_at AS createdAt FROM member
role = 'USER'
AND ( nickname LIKE CONCAT('%', #{keyword}, '%') OR email LIKE CONCAT('%', #{keyword}, '%') )
AND status = #{status}
ORDER BY created_at ${sortOrder}

mapper.update:
UPDATE member
SET status = #{status}
WHERE id = #{memberId}

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM auction
    WHERE seller_id = #{memberId}
      AND status = 'ON_GOING'
)

mapper.update:
UPDATE member
SET grade = #{grade}
WHERE id = #{memberId}

mapper.select:
SELECT auctionId, itemName, currentPrice, bidCount, endDate, auctionType, inspectionYn, saleStatus, imageUrl FROM ( SELECT a.id AS auctionId, ai.name AS itemName, COALESCE(a.winner_price, a.vickrey_price, a.start_price) AS currentPrice, a.bid_count AS bidCount, a.end_date AS endDate, a.type AS auctionType, a.inspection_yn AS inspectionYn, CASE WHEN a.status = 'PENDING' THEN 'PENDING' WHEN a.status = 'ON_GOING' THEN 'ONGOING' WHEN a.status = 'ENDED' AND a.winner_id IS NOT NULL THEN 'SUCCESS' WHEN a.status = 'ENDED' AND a.winner_id IS NULL THEN 'FAILED' WHEN a.status = 'CANCELLED' THEN 'CANCELLED' END AS saleStatus, ii.url AS imageUrl, a.created_at AS createdAt FROM auction a INNER JOIN auction_item ai ON a.item_id = ai.id LEFT JOIN item_image ii ON ii.item_id = ai.id AND ii.display_order = 1 WHERE a.seller_id = #{memberId} ) q WHERE #{type} = 'ALL' OR q.saleStatus = #{type}
ORDER BY q.createdAt ASC
ORDER BY q.createdAt DESC
LIMIT #{pageRequest.size} OFFSET #{pageRequest.offset}
